<!DOCTYPE html><html><head><meta charset="utf-8"><title>Patient Card</title><style>body{font-family:Arial,sans-serif}.card{width:420px;border:1px solid #111;padding:18px}.brand{color:#0f766e;font-weight:700}.label{font-size:12px;color:#555}@media print{button{display:none}}</style></head><body><div class="card"><p class="brand">{{ $facility?->name }}</p><h2>{{ $patient->fullName() }}</h2><p class="label">Patient Number</p><p>{{ $patient->patient_number }}</p><p>{{ $patient->gender->label() }} - {{ $patient->ageLabel() }}</p><p>{{ $patient->primary_phone ?? '-' }}</p><p>{{ $patient->primaryPayerProfile?->payer_type?->label() ?? 'Cash' }}</p><div style="margin-top:16px;border:1px dashed #555;padding:12px;text-align:center">QR Placeholder</div></div><button onclick="window.print()">Print</button></body></html>
